const e={id:46,title:"أبهر ضيوفك: نصائح احترافية لولائم احتفالية مثالية مع موقد الحث من إل جي وشفاط ThinQ®",excerpt:"تدور الاحتفالات حول خلق لحظات لا تُنسى، حيث تلتقي النكهات الرائعة مع التوقيت المثالي ومضيف مسترخٍ في المطبخ.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/Blog3_LGInductionHobInduction_.png?rand=d11d",href:"/sa_ar/kitchen-blog/dazzle-your-guest-lg-induction-hob-thinq-hood"},t=[{id:47,title:"نصائح الطهي في موسم الأعياد: تنظيف عميق بعد موسم الطهي في العطلات",excerpt:"يجمع موسم العطلات الأحباء ويملأ كل زاوية بالدفء، ويحول المطبخ إلى مركز حقيقي للنشاط الاحتفالي.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/Blog2_LGInstaviewOven.png?rand=ee99",href:"/sa_ar/kitchen-blog/festive-season-cooking-deep-cleaning-guide"},{id:48,title:"نصائح الطهي في موسم الأعياد: تحكّم دقيق في درجة الحرارة لوصفات الأعياد الحساسة",excerpt:"يدور موسم الأعياد حول التجمع معًا حول أطعمة مريحة مليئة بالنكهات.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/Blog4_LGCooktop.jpeg?rand=c4ba",href:"/sa_ar/kitchen-blog/smart-festive-season-cooking"}],i=[{id:49,title:"اهدِ وقتًا أكثر: بسّط الحياة اليومية مع ميكروويف إل جي",excerpt:"في عالمٍ يزداد انشغالًا، ليست أفضل هدية دائمًا باهظة أو فاخرة—بل هي ما يجعل الحياة اليومية أسهل فعلًا.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/Blog5_LGNeoChefMicrowaveOven.png?rand=ef5d",href:"/sa_ar/kitchen-blog/gift-power-of-time-lg-microwave-oven"},{id:50,title:"استخدام تطبيق ThinQ لتشغيل دورات التنظيف الذاتي وضمان أفضل أداء مع بداية العام الجديد",excerpt:"بداية عام جديد غالبًا ما تلهمنا لإعادة ترتيب المنزل، وتبسيط الروتين، واعتماد أساليب أذكى للعيش.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/Blog1_LGDISHWASHER.png?rand=0834",href:"/sa_ar/kitchen-blog/lg-dishwasher-self-clean-using-thinq"},{id:51,title:"نصائح الطهي في موسم الأعياد: تنظيف فعّال بعد وجبات العطلات",excerpt:"عندما يبدأ موسم الاحتفالات، يصبح مطبخك مركزًا نابضًا بالأنشطة والضيافة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Nov_Blog_02Main.jpg?rand=515a",href:"/sa_ar/kitchen-blog/festive-season-kitchen-cleanup-lg-dishwashers"},{id:52,title:"نصائح الطهي في موسم الأعياد: تحضير الأطباق الجانبية والصلصات للولائم الاحتفالية",excerpt:"موسم الأعياد يعني وجبات لا تُنسى. ورغم أن الطبق الرئيسي غالبًا ما يخطف الأضواء،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Nov_Blog_03.jpg?rand=aef4",href:"/sa_ar/kitchen-blog/festive-season-cooking-tips"},{id:53,title:"قلب إبداعاتك في الطهي: أساس موثوق وأنيق للوجبات المنزلية مع موقد إل جي الشعاعي",excerpt:"المطبخ هو المكان الذي تتحول فيه المكونات البسيطة إلى وجبات استثنائية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Nov_Blog_05.jpg?rand=a2aa",href:"/sa_ar/kitchen-blog/heart-of-your-culinary-creations"},{id:54,title:"استخدام التنبيهات الذكية في تطبيق ThinQ لضمان درجة حرارة مثالية لحفظ أطعمة الأعياد",excerpt:"عندما يصل الضيوف خلال موسم الاحتفالات، تُحضَّر عدة أطباق في الوقت نفسه وتكون الثلاجة في استخدام مستمر،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Nov_Blog_01.jpg?rand=5042",href:"/sa_ar/kitchen-blog/smart-alerts-lg-thinq-app"},{id:55,title:"ارتقِ بمطبخك للشتاء: إتقان أطعمة الراحة والكفاءة مع ميزات موقد الحث من إل جي وشفاط ThinQ®",excerpt:"الشتاء هو الوقت المثالي لترقية مساحة الطهي لديك بأجهزة مطبخ إل جي المبتكرة والموفّرة للطاقة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Nov_Blog_04.jpg?rand=358c",href:"/sa_ar/kitchen-blog/upgrade-your-kitchen-for-winter-lg-induction-hob"},{id:56,title:"استخدام خيارات إذابة التجميد الذكية في تطبيق ThinQ لمختلف المكونات المطلوبة...",excerpt:"عند التحضير لوجبة كبيرة، يكون الجزء الأكثر استهلاكًا للوقت هو تجهيز المكونات، خاصةً عندما تكون مجمّدة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KSA_BUILT-IN_Blog11.jpg",href:"/sa_ar/kitchen-blog/lg-smart-defrosting-thinq-app"},{id:57,title:"التحضير للتجمعات العائلية: تعظيم مساحة التخزين للمزيد...",excerpt:"أثناء التجمع العائلي، تصبح الثلاجة أحد المراكز الأساسية في المنزل...",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KSA_BUILT-IN_Blog2.jpg",href:"/sa_ar/kitchen-blog/lg-refrigerator-smart-cooling-efficiency-family-freshness"},{id:58,title:"تجمعات الخريف وأمسيات الذواقة: خلق أجواء مطبخ دافئة...",excerpt:"الخريف هو الوقت المثالي للتباطؤ وجمع الأحبة والاستمتاع بوجبات منزلية دافئة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KSA_BUILT-IN_Blog41.jpg",href:"/sa_ar/kitchen-blog/lg-induction-hob-autumn-cooking"},{id:59,title:"التحضير للتجمعات العائلية: التخطيط وإعداد وجبات أكبر",excerpt:"يُعدّ إعداد الوجبات للتجمعات العائلية متعة وتحديًا في الوقت نفسه...",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KSA_BUILT-IN_Blog31.jpg",href:"/sa_ar/kitchen-blog/family-gathering-meal-ideas-with-lg-electric-oven"},{id:60,title:"التحضير للتجمعات العائلية: إدارة عدة قدور ومقالي أثناء الطهي...",excerpt:"خلف كل وليمة شهية مشهد مزدحم من القدور التي تغلي والمقالي التي تَشْهَر...",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KSA_BUILT-IN_Blog51.jpg",href:"/sa_ar/kitchen-blog/cooking-for-family-gatherings-guide"},{id:61,title:"استخدام التحكّم الدقيق في درجة الحرارة عبر ThinQ لوصفات الخَبز الخريفية الحساسة",excerpt:"الخريف هو الوقت المثالي للاستمتاع بأجواء الخَبز الدافئة في المنزل. وخَبز الخريف ليس مجرد عادة موسمية؛ بل هو عملية خاصة تحتاج إلى عناية،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Built-In-KV_s_OCT_2048x1448_KV_01.jpg",href:"/sa_ar/kitchen-blog/fall-baking-smart-appliances"},{id:62,title:"تدفئة الشوربات وتحضير المشروبات الساخنة مع LG NeoChef™",excerpt:"مع برودة الطقس، لا شيء يضاهي وعاء شوربة دافئ أو كوبًا ساخنًا من مشروبك المفضل ليمنحك شعورًا بالدفء والراحة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Built-In-KV_s_OCT_2048x1448_KV_02.jpg",href:"/sa_ar/kitchen-blog/lg-neochef-microwave-oven"},{id:63,title:"الانتقال إلى أمسيات أكثر برودة: فحص الصيانة الدورية",excerpt:"مع اقتراب الخريف، تنتقل المطابخ في المنازل إلى “وضع النشاط العالي”.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Built-In-KV_s_OCT_2048x1448_KV_03.jpg",href:"/sa_ar/kitchen-blog/dishwasher-maintenance-tips"},{id:64,title:"الانتقال إلى أمسيات أكثر برودة: وصفات أطعمة مريحة مع انخفاض درجات الحرارة",excerpt:"مع بدء انخفاض درجات الحرارة وطول الأمسيات، يصبح الوقت مثاليًا للاستمتاع بوجبات مريحة تدفئ منزلك وقلبك.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Built-In-KV_s_OCT_2048x1448_KV_04.jpg",href:"/sa_ar/kitchen-blog/comfort-food-recipes"},{id:65,title:"صحي ومتعدد الاستخدامات: إعداد أطباق مغذية بدقة على موقد إل جي",excerpt:"الاهتمام بالصحة والرفاهية يبدأ من المطبخ، لذا فإن الطهي بوعي أمرٌ أساسي. وعند إعداد وجبات صحية ومغذية،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGE_SJ_Built-In-KV_s_OCT_2048x1448_KV_05.jpg",href:"/sa_ar/kitchen-blog/lg-hobs-for-healthy-cooking"},{id:66,title:"طهي موسم الحصاد بسهولة وروتين أكثر سلاسة: موقد الحث من إل جي وThinQ®",excerpt:"مع تغيّر الفصول ووصول موسم الحصاد، يصبح الطهي في المنزل مريحًا ومميزًا. إنه المكان لصنع طعام للأحبة،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog11.jpg",href:"/sa_ar/kitchen-blog/effortless-harvest-cooking"},{id:67,title:"موقد شعاعي كهربائي + شفاط: التركيز على ميزات السلامة خلال...",excerpt:"مع انتهاء الإجازات الصيفية والعودة إلى روتين المدرسة والعمل المزدحم، تصبح إدارة الوقت أكثر أهمية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog21.jpg",href:"/sa_ar/kitchen-blog/electric-radiant-hob-hood"},{id:68,title:"العودة إلى المدرسة: تنظيم يسهّل الوصول إلى وجبات الغداء...",excerpt:"مع انتهاء الصيف وبدء الدراسة من جديد، يعرف الآباء جيدًا مدى انشغال الصباح — إعداد وجبات الغداء،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog31.jpg",href:"/sa_ar/kitchen-blog/back-to-school"},{id:69,title:"كفاءة العودة إلى المدرسة/العمل: خيارات الدورة السريعة لتنظيف أسرع...",excerpt:"مع انتهاء الإجازات الصيفية والعودة إلى روتين المدرسة والعمل المزدحم، تصبح إدارة الوقت أكثر أهمية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog41.jpg",href:"/sa_ar/kitchen-blog/back-to-school-work-efficiency"},{id:70,title:"طهي ذكي لحياة أكثر سلاسة: دمج فرن إل جي في روتينك اليومي...",excerpt:"في عالمٍ سريع الوتيرة، من الصعب إيجاد وقت للطهي مع موازنة العمل والعائلة والمهام الشخصية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog51.jpg",href:"/sa_ar/kitchen-blog/smart-cooking-for-a-seamless"},{id:71,title:"استخدام تطبيق LG ThinQ لمراقبة موقد ThinQ عن بُعد وضمان السلامة...",excerpt:"لا حاجة للوقوف فوق الموقد لساعات. مع أفران InstaView من إل جي والميكروويف المدمج، يمكنك إعادة التسخين باحتراف، والتحضير بدقة، وتقديم الطعام بثقة.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog1.jpg",href:"/sa_ar/kitchen-blog/using-lg-thinq-app"},{id:72,title:"تغلّب على حرارة الصيف: طهي ذكي وسريع مع موقد الحث من إل جي...",excerpt:"عندما ترتفع درجات حرارة الصيف، قد يبدو الطهي في مطبخ ساخن أمرًا مرهقًا. لكن لا بد من تحضير الوجبات،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog2.jpg",href:"/sa_ar/kitchen-blog/beat-the-summer-heat"},{id:73,title:"مواجهة حرارة المطبخ: تحضيرات وجبات سريعة ومنعشة.",excerpt:"الطقس الدافئ يغيّر كل شيء—من ما تأكله إلى كيفية تحضيره. يجلب الصيف الإجازات والكثير من النشاط،",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog3.jpg",href:"/sa_ar/kitchen-blog/beating-the-heat-in-the-kitchen"},{id:74,title:"InstaView: محطة المرطّبات لتجمعات الصيف",excerpt:"الطقس الدافئ يغيّر كل شيء—من ما تأكله إلى كيفية تحضيره. يجلب الصيف الإجازات والكثير من النشاط والاستمتاع بوجبات طازجة وحيوية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGESJBlog5.jpg",href:"/sa_ar/kitchen-blog/instaview-your-refreshment"},{id:75,title:"استكشاف وصفات ThinQ وأوضاع الطهي الذكية المصممة لوجبات صيفية أخف.",excerpt:"عندما ترتفع درجات الحرارة خلال صيف السعودية، تبحث العائلات عن طرق جديدة للطهي وتناول الطعام براحة أكبر.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KV_01_ThinQ-1.png",href:"/sa_ar/kitchen-blog/exploring-thinq-recipes-and-smart-cooking-modes-design-for-lighter-summer-meals"},{id:76,title:"ترفيه الصيف: نصائح سلامة عند وجود الأطفال أو الضيوف خلال الفعاليات الخارجية...",excerpt:"التجمعات الخارجية طريقة رائعة للاستمتاع بالأيام المشمسة مع العائلة والأصدقاء، لكن يجب أن تكون السلامة دائمًا في المقام الأول خصوصًا عند وجود أطفال.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KV_03_Outdoor1.png",href:"/sa_ar/kitchen-blog/summer-entertaining-safety-tips"},{id:77,title:"تقنيات طهي فعّالة لوجبات صيفية سريعة.",excerpt:"الطقس الدافئ يغيّر كل شيء—من ما تأكله إلى كيفية تحضيره. يجلب الصيف الإجازات والكثير من النشاط والاستمتاع بوجبات طازجة وحيوية.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/KV_02_EfficientCooking1.png",href:"/sa_ar/kitchen-blog/efficient-cooking-techniques-for-quick-summer-meals"},{id:78,title:"وصفة حلوى صيفية مع أجهزة إل جي المدمجة",excerpt:"الصيف في السعودية يعني درجات حرارة مرتفعة وأيامًا طويلة مشمسة. حرارة الشمس تمنحك عذرًا مثاليًا لتدلّل نفسك بشيء بارد ولذيذ.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/islands-interior1.png",href:"/sa_ar/kitchen-blog/summer-dessert-recipe"},{id:79,title:"تعزيز طهي رمضان مع أجهزة إل جي المدمجة",excerpt:"اجعل رمضانك أفضل مع أجهزة إل جي المدمجة التي تجمع بين الأناقة والراحة. اصنع لحظات مطبخ لا تُنسى...",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/built-in-appliances.webp",href:"/sa_ar/kitchen-blog/enhancing-ramadan-cooking"},{id:80,title:"دليلك لأفضل أجهزة الطهي المدمجة",excerpt:"يساعد شفاط المطبخ على إزالة الحرارة الزائدة والرطوبة والدهون والدخان والجسيمات المحمولة في الهواء، ما يضمن بيئة طهي أكثر صحة. لذا فإن الحفاظ عليه نظيفًا هو المفتاح لمطبخ نظيف ومنتعش.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/LGBuilt-inAppliancesLifestyleBrown.png",href:"/sa_ar/kitchen-blog/your-guide-to-the-best"},{id:81,title:"تنظيف شفاط المطبخ: دليل خطوة بخطوة",excerpt:"اكتشف كيفية إتقان تنظيف شفاط المطبخ عبر دليلنا خطوة بخطوة لضمان بيئة طهي أكثر صحة وانتعاشًا. تعلّم نصائح فعّالة اليوم!",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/BestWaytoCleanaHood.png",href:"/sa_ar/kitchen-blog/kitchen-hood-cleaning"},{id:82,title:"الدليل الشامل لدرجات حرارة الفرن",excerpt:"أتقن فن الطهي مع الدليل الشامل لدرجات حرارة الفرن! اكتشف درجة الحرارة المناسبة للخبز والتحميص والمزيد. اعرف أكثر.",image:"https://www.lg.com/ae/lg-story/helpful-guide/oven-temperature-guide/lg-microwave-oven.png",href:"/sa_ar/kitchen-blog/oven-temperature-guide"},{id:91,title:"أفضل غسالات صحون إل جي لمطبخ نظيف",excerpt:"اعثر على أفضل غسالات صحون إل جي المصممة لتنظيف مثالي وكفاءة في استهلاك الطاقة وتصميم أنيق.",image:"https://www.lg.com/ae/lg-story/helpful-guide/best-lg-dishwashers-for-a-clean-kitchen/dishwasher.png",href:"/sa_ar/kitchen-blog/best-lg-diswashers"},{id:92,title:"كيفية استخدام غسالة الصحون: دليلك الشامل",excerpt:"اكتشف الدليل الشامل لاستخدام غسالة الصحون بكفاءة وأمان. تعرّف على نصائح الصيانة ومزايا الجهاز.",image:"https://www.lg.com/ae/lg-story/helpful-guide/how-to-use-a-dishwasher-your-ultimate-guide/Everything%20About%20Dishwasher.jpg",href:"/sa_ar/kitchen-blog/how-to-use-a-dishwasher"},{id:85,title:"3 وصفات سهلة بالميكروويف يجب تجربتها",excerpt:"الميكروويف ليس فقط لإعادة تسخين بقايا الطعام. اضغط لاكتشاف 3 وصفات لا بد من تجربتها اليوم ومعرفة المزيد عن ميكروويفات إل جي.",image:"https://www.lg.com/ae/lg-story/helpful-guide/3-must-try-easy-microwave-recipes/Easy-Microwave-Recipes-LG-UAE.jpg",href:"/sa_ar/kitchen-blog/3-must-try-easy-microwave"},{id:86,title:"مشكلات الميكروويف الشائعة وحلول سريعة",excerpt:"اكتشف حلولًا لمشكلات الميكروويف الشائعة، من التسخين غير المتساوي إلى الأصوات الغريبة. تعلّم حلولًا سريعة للحفاظ على أداء ميكروويفك بسلاسة مع LG Story.",image:"https://www.lg.com/ae/lg-story/helpful-guide/common-microwave-issues-and-quick-fixes/microwave.png",href:"/sa_ar/kitchen-blog/common-microwave-issue"},{id:87,title:"أفضل أفران الميكروويف لمنزلك",excerpt:"اكتشف أفضل فرن ميكروويف لعام 2025 وميزاته مثل القدرة (الواط) والسعة باللتر. تعلّم كيفية اختيار الميكروويف المثالي من خلال دليلنا.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/oven.jpg",href:"/sa_ar/kitchen-blog/the-best-microwave-oven"},{id:93,title:"كيفية اختيار غسالة صحون موفّرة للطاقة",excerpt:"هل تبحث عن غسالة صحون موفّرة للطاقة وفعّالة في الوقت نفسه؟ ستجد هنا أفضل الخيارات التي تلبي احتياجاتك من إل جي! اضغط الآن.",image:"https://lgkitchenplanner.com/sa_en/kitchen-blog/images/image6.png",href:"/sa_ar/kitchen-blog/how-to-choose-an-energy-saving"},{id:94,title:"لماذا يجب أن تمتلك غسالة صحون إل جي في مطبخك",excerpt:"من الضروري لكل منزل امتلاك أفضل مطبخ وأكثره راحة، لأنه المكان الذي يجتمع فيه أفراد العائلة لتناول العشاء أو إعداد وجبة خفيفة والحديث معًا.",image:"https://www.lg.com/ae/lg-story/images/blog-home-thumb/Dishwasher-Thumb.jpg",href:"/sa_ar/kitchen-blog/lg-dishwasher-in-your-kitchen"},{id:90,title:"كيفية تنظيف ميكروويف سولو",excerpt:"هل تريد معرفة كيفية تنظيف الميكروويف بسرعة؟ اضغط لتعلّم خطوات تنظيف الميكروويف وما الذي يجعل ميكروويفات إل جي السولو سهلة التنظيف والاستخدام!",image:"https://www.lg.com/ae/lg-story/helpful-guide/how-to-clean-your-solo-microwave/LG-Microwave-cleaning-LG-UAE.JPG",href:"/sa_ar/kitchen-blog/how-to-clean-your-microwave"}],n={featuredPost:e,topSidePosts:t,regularPosts:i};export{n as default,e as featuredPost,i as regularPosts,t as topSidePosts};
